INSERT INTO idea_templates (title, description, category, cost_level, estimated_cost_min, estimated_cost_max, duration_minutes, vibe_tags, requires_reservation, outdoor_only, seasonal, dietary_friendly, search_keywords, venue_type, setting_type, intensity_level, quick_filters, reservation_platforms)
SELECT title, description, category, cost_level, estimated_cost_min, estimated_cost_max, duration_minutes, vibe_tags, requires_reservation, outdoor_only, seasonal, dietary_friendly, search_keywords, venue_type, setting_type, intensity_level, quick_filters, reservation_platforms
FROM jsonb_to_recordset($dn$[{"title":"Underground Warehouse Dance Party","description":"You follow a string of dim filament bulbs down an alley to an unmarked door, then spill into a converted warehouse where the bass rattles your sternum and strangers become a single moving crowd. By 2 a.m. you're both soaked through and laughing, trading shouted song requests with the DJ and splitting a bottle of water like it's champagne.","category":"entertainment","cost_level":2,"estimated_cost_min":40,"estimated_cost_max":70,"duration_minutes":240,"vibe_tags":["fun","adventurous","social","active"],"requires_reservation":false,"outdoor_only":false,"seasonal":null,"dietary_friendly":[],"search_keywords":["warehouse party","underground dance club","late night DJ set","rave","nightlife"],"venue_type":"nightclub","setting_type":"big_city","intensity_level":3,"quick_filters":["active","fun_silly"],"reservation_platforms":["eventbrite","google_maps"]},{"title":"Bridge-to-Bridge Skyline Run","description":"You lace up at dusk and trace the river's edge together, the two of you setting a pace that turns the city's bridges into a glowing checkpoint course. When you finally stop, breathless, the downtown towers are mirrored in the water and you toast the finish line with cold lime sodas from a corner cart.","category":"outdoor","cost_level":1,"estimated_cost_min":0,"estimated_cost_max":15,"duration_minutes":90,"vibe_tags":["active","adventurous","fun"],"requires_reservation":false,"outdoor_only":true,"seasonal":["spring","summer","fall"],"dietary_friendly":["vegan","vegetarian","gluten-free","dairy-free"],"search_keywords":["urban running route","waterfront run","skyline jog","city bridges","running path"],"venue_type":null,"setting_type":"big_city","intensity_level":3,"quick_filters":["active","low_budget"],"reservation_platforms":["google_maps"]},{"title":"All-Night Neighborhood Crawl","description":"You start with dumplings in Chinatown at 6 and let momentum carry you through speakeasies, a 24-hour diner, and a rooftop where the sun comes up over the financial district. Somewhere around 4 a.m. you stop counting neighborhoods and just keep walking, the empty streets feeling like the city belongs only to the two of you.","category":"activity","cost_level":3,"estimated_cost_min":90,"estimated_cost_max":150,"duration_minutes":720,"vibe_tags":["adventurous","fun","social","foodie"],"requires_reservation":false,"outdoor_only":false,"seasonal":null,"dietary_friendly":["vegetarian"],"search_keywords":["all night city crawl","neighborhood bar hop","24 hour diner","sunrise rooftop","late night food"],"venue_type":null,"setting_type":"big_city","intensity_level":4,"quick_filters":["fun_silly","active"],"reservation_platforms":["yelp","google_maps"]},{"title":"Penthouse Suite Staycation","description":"You check into a top-floor suite where floor-to-ceiling glass turns the skyline into your private wallpaper, ordering room service in robes and never once touching the elevator down. Late at night you trade the soaking tub for the cool windowsill, naming the buildings you can see and inventing lives for the lit-up windows across the way.","category":"relaxation","cost_level":4,"estimated_cost_min":350,"estimated_cost_max":600,"duration_minutes":1440,"vibe_tags":["fancy","romantic","relaxing","cozy"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":[],"search_keywords":["luxury hotel suite","penthouse staycation","skyline hotel","room service overnight","city hotel getaway"],"venue_type":"hotel","setting_type":"big_city","intensity_level":2,"quick_filters":["luxury","romantic"],"reservation_platforms":["google_maps","yelp"]},{"title":"Helicopter City Lights Flight","description":"You strap into headsets as the rotors spin up, then lift off the downtown helipad and watch the grid of streets ignite into a circuit board of gold beneath you. For twenty minutes the whole skyline tilts past your window, and you keep squeezing each other's hands every time the pilot banks toward another glittering landmark.","category":"activity","cost_level":4,"estimated_cost_min":200,"estimated_cost_max":400,"duration_minutes":120,"vibe_tags":["adventurous","romantic","fancy"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":[],"search_keywords":["helicopter tour","city lights flight","skyline helicopter ride","aerial city tour","night flight"],"venue_type":null,"setting_type":"big_city","intensity_level":3,"quick_filters":["luxury","romantic"],"reservation_platforms":["airbnb_experiences","google_maps"]},{"title":"Chef's Tasting + Symphony Night","description":"You begin with a multi-course tasting menu near the concert hall, dressing up just enough to feel like the evening is about more than dinner. Then you slip into velvet seats as the orchestra tunes, and the way the first downbeat lands makes you reach for each other's hand in the dark.","category":"cultural","cost_level":3,"estimated_cost_min":110,"estimated_cost_max":150,"duration_minutes":240,"vibe_tags":["fancy","romantic","cultural","foodie"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":["vegetarian","gluten-free"],"search_keywords":["symphony orchestra night","tasting menu before concert","concert hall date","fine dining and music","classical performance"],"venue_type":"concert hall","setting_type":"big_city","intensity_level":2,"quick_filters":["romantic","intellectual"],"reservation_platforms":["opentable","resy","eventbrite"]},{"title":"Trampoline Park Showdown","description":"Lace up the grippy socks and bounce wall-to-wall through foam pits, dodgeball courts, and a slam-dunk lane that finally makes you both feel six feet tall. You'll collapse onto the side bench breathless and laughing, daring each other to one more round before your legs give out.","category":"activity","cost_level":2,"estimated_cost_min":35,"estimated_cost_max":65,"duration_minutes":120,"vibe_tags":["fun","active","social"],"requires_reservation":false,"outdoor_only":false,"seasonal":null,"dietary_friendly":[],"search_keywords":["trampoline park","indoor trampoline","jump park","dodgeball court"],"venue_type":"entertainment","setting_type":"suburbs","intensity_level":3,"quick_filters":["fun_silly","active"],"reservation_platforms":["yelp","google_maps"]},{"title":"Pickleball Doubles Clinic","description":"Grab two paddles at the neighborhood rec complex and join a drop-in doubles session where strangers quickly become your weirdly competitive new friends. Between dinks and missed serves, you'll high-five sweaty palms and start plotting a standing weekly game on the way to the smoothie counter.","category":"activity","cost_level":1,"estimated_cost_min":10,"estimated_cost_max":30,"duration_minutes":90,"vibe_tags":["active","fun","social"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":[],"search_keywords":["pickleball","doubles clinic","rec center courts","drop-in pickleball"],"venue_type":"recreation center","setting_type":"suburbs","intensity_level":3,"quick_filters":["active","fun_silly","low_budget"],"reservation_platforms":["meetup","yelp","google_maps"]},{"title":"Neighborhood Amazing Race","description":"Build a half-day scavenger gauntlet across your own suburb, racing between the library drop box, the splash pad, a thrift store mystery purchase, and a coffee-shop riddle you texted ahead to the barista. By the final checkpoint you'll be sprinting through a strip-mall parking lot, sweaty and victorious, having seen your sleepy town like contestants on a reality show.","category":"activity","cost_level":2,"estimated_cost_min":40,"estimated_cost_max":70,"duration_minutes":360,"vibe_tags":["adventurous","active","fun"],"requires_reservation":false,"outdoor_only":false,"seasonal":["spring","summer","fall"],"dietary_friendly":["vegetarian"],"search_keywords":["scavenger hunt","amazing race","town challenge","checkpoint race"],"venue_type":null,"setting_type":"suburbs","intensity_level":4,"quick_filters":["active","fun_silly"],"reservation_platforms":["google_maps","yelp"]},{"title":"Boutique Motel Staycation","description":"Book a night at the quirky retro-renovated motel two exits down, the one with the neon sign and the kidney-shaped pool nobody from out of town ever notices. You'll cannonball at midnight, raid the corner gas station for poolside snacks, and wake up feeling like you took a real trip without ever leaving the zip code.","category":"relaxation","cost_level":2,"estimated_cost_min":60,"estimated_cost_max":75,"duration_minutes":1440,"vibe_tags":["cozy","fun","relaxing","social"],"requires_reservation":true,"outdoor_only":false,"seasonal":["spring","summer"],"dietary_friendly":[],"search_keywords":["boutique motel","retro motel","staycation","motel pool"],"venue_type":"motel","setting_type":"suburbs","intensity_level":4,"quick_filters":["fun_silly","romantic"],"reservation_platforms":["airbnb_experiences","google_maps","yelp"]},{"title":"Strip-Mall Supper Club","description":"Track down the unassuming chef-driven spot tucked between a nail salon and a dry cleaner, where a fixed multi-course menu turns out to rival anything downtown. You'll order the off-menu pairing the owner recommends, marvel that this gem hides behind a parking lot, and trade the satisfied smugness of locals who found it first.","category":"restaurant","cost_level":3,"estimated_cost_min":90,"estimated_cost_max":140,"duration_minutes":150,"vibe_tags":["foodie","romantic","fancy"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":["vegetarian","gluten-free"],"search_keywords":["hidden gem restaurant","supper club","tasting menu","neighborhood bistro"],"venue_type":"restaurant","setting_type":"suburbs","intensity_level":2,"quick_filters":["romantic","luxury"],"reservation_platforms":["resy","opentable","yelp"]},{"title":"Sunrise Hot Air Balloon Liftoff","description":"Meet the crew in a dew-soaked soccer field at first light and rise silently over cul-de-sacs, backyard pools, and the highway interchange shrinking beneath your basket. You'll toast with champagne while the burner roars warm against your faces, watching your whole ordinary suburb turn into a glowing patchwork far below.","category":"outdoor","cost_level":4,"estimated_cost_min":300,"estimated_cost_max":500,"duration_minutes":240,"vibe_tags":["romantic","adventurous","fancy"],"requires_reservation":true,"outdoor_only":true,"seasonal":["spring","summer","fall"],"dietary_friendly":[],"search_keywords":["hot air balloon ride","sunrise balloon","champagne flight","balloon tour"],"venue_type":null,"setting_type":"suburbs","intensity_level":3,"quick_filters":["romantic","luxury"],"reservation_platforms":["airbnb_experiences","yelp","google_maps"]},{"title":"Tide Pool Tracking at Low Tide","description":"You time your arrival to the morning's lowest tide, then scramble across slick black rocks chasing the retreating water into a maze of secret pools. Crouched shoulder to shoulder, you discover anemones that curl shut at your touch and a startled crab who scuttles between your fingers as the spray catches the sun.","category":"outdoor","cost_level":1,"estimated_cost_min":0,"estimated_cost_max":25,"duration_minutes":150,"vibe_tags":["adventurous","active","fun"],"requires_reservation":false,"outdoor_only":true,"seasonal":["spring","summer"],"dietary_friendly":[],"search_keywords":["tide pools","low tide","rocky shore","coastal exploration","marine life"],"venue_type":null,"setting_type":"coastal","intensity_level":3,"quick_filters":["active","low_budget","intellectual"],"reservation_platforms":["nps","recreation_gov","google_maps"]},{"title":"Beginner Surf Lesson in the Break","description":"You wrestle into damp wetsuits and paddle out together, laughing every time a wave knocks one of you sideways before you've even stood up. Then it happens for real, you pop to your feet for three glorious seconds while they whoop from the whitewater behind you, both of you salt-stung and grinning like idiots.","category":"activity","cost_level":2,"estimated_cost_min":60,"estimated_cost_max":75,"duration_minutes":180,"vibe_tags":["adventurous","active","fun"],"requires_reservation":true,"outdoor_only":true,"seasonal":["summer"],"dietary_friendly":[],"search_keywords":["surf lesson","learn to surf","beach","wetsuit","ocean waves"],"venue_type":"surf school","setting_type":"coastal","intensity_level":3,"quick_filters":["active","fun_silly"],"reservation_platforms":["airbnb_experiences","yelp","google_maps"]},{"title":"Overnight Sailing Charter","description":"You provision a small chartered sailboat at the marina and point the bow toward open water, taking turns at the helm as the coastline shrinks behind you into a thin gold line. After anchoring in a quiet cove, you cook dinner in the galley and fall asleep to the hull knocking gently against the swell, waking to coffee on deck and nothing but horizon.","category":"outdoor","cost_level":4,"estimated_cost_min":600,"estimated_cost_max":1200,"duration_minutes":1440,"vibe_tags":["adventurous","romantic","active"],"requires_reservation":true,"outdoor_only":true,"seasonal":["summer","fall"],"dietary_friendly":[],"search_keywords":["sailing charter","overnight sailboat","marina","anchor in cove","private sail"],"venue_type":"marina","setting_type":"coastal","intensity_level":4,"quick_filters":["active","luxury","romantic"],"reservation_platforms":["airbnb_experiences","google_maps","yelp"]},{"title":"Coastal Trail Backpacking Overnight","description":"You shoulder loaded packs at the trailhead and walk the bluff-edge path for miles, the surf booming below you and the wind pushing the smell of kelp up the cliff face. By dusk you've pitched a tent on a grassy headland, sharing a foil-wrapped dinner heated over a tiny stove while fog rolls in and the lighthouse down the coast starts to blink.","category":"outdoor","cost_level":2,"estimated_cost_min":30,"estimated_cost_max":70,"duration_minutes":1440,"vibe_tags":["adventurous","active","romantic"],"requires_reservation":true,"outdoor_only":true,"seasonal":["spring","summer","fall"],"dietary_friendly":["vegetarian"],"search_keywords":["coastal backpacking","bluff trail","headland camping","overnight hike","sea cliffs"],"venue_type":null,"setting_type":"coastal","intensity_level":4,"quick_filters":["active","low_budget","romantic"],"reservation_platforms":["recreation_gov","nps","google_maps"]},{"title":"Oyster Bar Raw Counter","description":"You slide onto stools at a marble counter where the shucker works an arm's length away, sliding you briny half-shells fresh from the harbor that morning. Squeezing lemon and clinking crisp glasses of muscadet, you debate which bay tastes sweetest while the sunset turns the dock pilings outside a deep copper.","category":"restaurant","cost_level":3,"estimated_cost_min":80,"estimated_cost_max":140,"duration_minutes":120,"vibe_tags":["foodie","romantic","fancy"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":["gluten-free","dairy-free"],"search_keywords":["oyster bar","raw bar","fresh oysters","harbor seafood","shucking counter"],"venue_type":"restaurant","setting_type":"coastal","intensity_level":2,"quick_filters":["romantic","luxury"],"reservation_platforms":["resy","opentable","yelp"]},{"title":"Private Sunset Catamaran Cruise","description":"You step aboard a sleek catamaran reserved just for the two of you, settling into the netting at the bow with chilled champagne as the captain eases the boat past the breakwater. As the sun melts into the water and dolphins arc alongside the hull, a crew member appears with a tray of seared scallops and you toast the salt-pink sky.","category":"outdoor","cost_level":4,"estimated_cost_min":350,"estimated_cost_max":600,"duration_minutes":180,"vibe_tags":["romantic","fancy","relaxing"],"requires_reservation":true,"outdoor_only":true,"seasonal":["summer","fall"],"dietary_friendly":["gluten-free","dairy-free"],"search_keywords":["private catamaran","sunset cruise","champagne sail","harbor sunset","luxury boat charter"],"venue_type":"marina","setting_type":"coastal","intensity_level":2,"quick_filters":["romantic","luxury"],"reservation_platforms":["airbnb_experiences","yelp","google_maps"]},{"title":"Via Ferrata Cliff Traverse","description":"You clip your harness into the steel cable bolted across a sheer granite face and inch along iron rungs with nothing but mountain air beneath your boots, trading nervous laughs with every handhold. By the time you reach the exposed ledge, the valley sprawls a thousand feet below and your hearts are pounding for two very different reasons.","category":"outdoor","cost_level":2,"estimated_cost_min":60,"estimated_cost_max":75,"duration_minutes":240,"vibe_tags":["adventurous","active"],"requires_reservation":true,"outdoor_only":true,"seasonal":["summer","fall"],"dietary_friendly":[],"search_keywords":["via ferrata","iron way climbing","cliff traverse","guided mountain climb","exposure adventure"],"venue_type":null,"setting_type":"mountain","intensity_level":3,"quick_filters":["active","fun_silly"],"reservation_platforms":["airbnb_experiences","recreation_gov","yelp"]},{"title":"Alpine Trail Run to a Tarn","description":"You lace up at the trailhead before the heat builds, then chase each other up switchbacks where the pines thin into stunted krummholz and the air goes sharp and cold. The reward is a glassy alpine tarn cupped in the rock, where you peel off sweaty shoes and dunk your feet in snowmelt until your toes go numb and you can't stop grinning.","category":"activity","cost_level":1,"estimated_cost_min":0,"estimated_cost_max":15,"duration_minutes":180,"vibe_tags":["active","adventurous","fun"],"requires_reservation":false,"outdoor_only":true,"seasonal":["summer"],"dietary_friendly":[],"search_keywords":["alpine trail run","mountain tarn","high country run","switchback trail","snowmelt lake"],"venue_type":null,"setting_type":"mountain","intensity_level":3,"quick_filters":["active","low_budget"],"reservation_platforms":["recreation_gov","nps"]},{"title":"Overnight Hut-to-Hut Trek","description":"You shoulder light packs and spend the day climbing through fir forest into open high country, navigating by map and ridgeline until a backcountry hut appears like a promise at dusk. Inside you split a freeze-dried feast by lantern light, then step out to a sky so thick with stars it feels like the mountain is holding its breath just for the two of you.","category":"outdoor","cost_level":2,"estimated_cost_min":50,"estimated_cost_max":75,"duration_minutes":1440,"vibe_tags":["adventurous","active","romantic"],"requires_reservation":true,"outdoor_only":true,"seasonal":["summer","fall"],"dietary_friendly":["vegetarian"],"search_keywords":["hut to hut trek","backcountry hut","overnight mountain hike","alpine hut booking","multi day trek"],"venue_type":null,"setting_type":"mountain","intensity_level":4,"quick_filters":["active","intellectual"],"reservation_platforms":["recreation_gov","nps"]},{"title":"Summit Sunrise Backpacking Push","description":"You set an alarm for the dark side of 3 a.m. and climb by headlamp through switchbacks of scree, your breath fogging and your conversation dropping to whispers as the peak nears. When the first light cracks over the eastern ranges and floods the summit gold, you huddle under one shared blanket and watch the whole world wake up beneath your feet.","category":"outdoor","cost_level":1,"estimated_cost_min":0,"estimated_cost_max":20,"duration_minutes":600,"vibe_tags":["adventurous","romantic","active"],"requires_reservation":true,"outdoor_only":true,"seasonal":["summer"],"dietary_friendly":[],"search_keywords":["sunrise summit","alpine start","overnight backpacking","peak bagging","predawn climb"],"venue_type":null,"setting_type":"mountain","intensity_level":4,"quick_filters":["active","romantic"],"reservation_platforms":["recreation_gov","nps"]},{"title":"Gondola Dinner at the Peak","description":"You ride a glass gondola up the mountain as the lift towers swing past below, then step out at a summit chalet where white tablecloths glow against a backdrop of darkening ridgelines. Over a multi-course alpine dinner you watch the lights of the valley town flicker on far beneath you, the whole evening suspended somewhere between earth and sky.","category":"restaurant","cost_level":3,"estimated_cost_min":90,"estimated_cost_max":140,"duration_minutes":180,"vibe_tags":["romantic","fancy","foodie"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":["vegetarian","gluten-free"],"search_keywords":["gondola dinner","summit restaurant","mountaintop dining","alpine chalet dinner","scenic lift dining"],"venue_type":"restaurant","setting_type":"mountain","intensity_level":2,"quick_filters":["romantic","luxury"],"reservation_platforms":["opentable","resy","yelp"]},{"title":"Mountain Lodge Heli-Picnic","description":"A helicopter lifts you off a lodge helipad and banks over knife-edge ridges before setting down on a remote alpine meadow no trail can reach, where a private chef has laid out a chilled picnic among the wildflowers. You sip champagne with glaciers gleaming on every horizon, completely alone on a mountaintop that feels like it was carved out of the day just for the two of you.","category":"outdoor","cost_level":4,"estimated_cost_min":600,"estimated_cost_max":1200,"duration_minutes":240,"vibe_tags":["romantic","fancy","adventurous","foodie"],"requires_reservation":true,"outdoor_only":true,"seasonal":["summer"],"dietary_friendly":["vegetarian","gluten-free"],"search_keywords":["heli picnic","helicopter alpine meadow","private mountain picnic","luxury heli experience","glacier champagne picnic"],"venue_type":"resort","setting_type":"mountain","intensity_level":3,"quick_filters":["luxury","romantic"],"reservation_platforms":["airbnb_experiences","google_maps"]},{"title":"Slot Canyon Scramble","description":"You squeeze single-file through a slot canyon barely wider than your shoulders, the sandstone walls glowing amber where the noon light slips down to find you. Every twist opens a new chamber of swirled rock, and you keep stopping to press your palms against the cool, water-carved curves while your voices echo back doubled.","category":"outdoor","cost_level":1,"estimated_cost_min":0,"estimated_cost_max":25,"duration_minutes":240,"vibe_tags":["adventurous","active","romantic"],"requires_reservation":false,"outdoor_only":true,"seasonal":["spring","fall"],"dietary_friendly":[],"search_keywords":["slot canyon","canyon hike","sandstone narrows","desert hiking","antelope canyon style"],"venue_type":null,"setting_type":"desert","intensity_level":3,"quick_filters":["active","low_budget","romantic"],"reservation_platforms":["recreation_gov","nps","google_maps"]},{"title":"Dune Sandboarding Run","description":"You haul waxed boards to the crest of a wind-sculpted dune and stand catching your breath as the desert spills out gold in every direction. One push and you're carving down the slope in a hiss of sand, then trudging back up laughing, knees burning, to do it all over again until the light goes pink.","category":"activity","cost_level":2,"estimated_cost_min":35,"estimated_cost_max":70,"duration_minutes":180,"vibe_tags":["adventurous","active","fun"],"requires_reservation":true,"outdoor_only":true,"seasonal":["fall","winter","spring"],"dietary_friendly":[],"search_keywords":["sandboarding","dune boarding","sand dunes","desert dunes","sand sledding"],"venue_type":null,"setting_type":"desert","intensity_level":3,"quick_filters":["active","fun_silly"],"reservation_platforms":["recreation_gov","airbnb_experiences","yelp"]},{"title":"Hot Air Balloon Over the Canyonlands","description":"You lift off in the cold blue hush before dawn, the burner roaring overhead as the desert floor drops away into a maze of mesas, washes, and red rock spires. As the sun crests the horizon the whole landscape ignites beneath your basket, and you clink a thermos of coffee while floating in total silence above a thousand square miles of stone.","category":"outdoor","cost_level":4,"estimated_cost_min":300,"estimated_cost_max":500,"duration_minutes":300,"vibe_tags":["adventurous","romantic","fancy"],"requires_reservation":true,"outdoor_only":true,"seasonal":["fall","winter","spring"],"dietary_friendly":[],"search_keywords":["hot air balloon","balloon ride","desert sunrise flight","canyon balloon","scenic flight"],"venue_type":null,"setting_type":"desert","intensity_level":4,"quick_filters":["luxury","romantic","active"],"reservation_platforms":["airbnb_experiences","google_maps","yelp"]},{"title":"Backcountry Jeep Overnight","description":"You bounce for hours down rutted washboard roads deep into roadless desert, the cab fogging with dust as red buttes scroll past and cell signal disappears entirely. By dusk you've pitched camp on a slab of slickrock, cooked dinner over a single burner, and spread your bags out under a sky so thick with stars you can see your hands by them.","category":"outdoor","cost_level":3,"estimated_cost_min":120,"estimated_cost_max":220,"duration_minutes":1440,"vibe_tags":["adventurous","active","romantic","cozy"],"requires_reservation":true,"outdoor_only":true,"seasonal":["fall","spring"],"dietary_friendly":[],"search_keywords":["overlanding","jeep camping","backcountry desert","4x4 trail","dispersed camping"],"venue_type":null,"setting_type":"desert","intensity_level":4,"quick_filters":["active","romantic"],"reservation_platforms":["recreation_gov","nps","airbnb_experiences"]},{"title":"Cliffside Casita Cookout","description":"You rent a low adobe casita perched at a canyon's edge and grill green chile and corn on the back patio as the cliff face across the wash turns from ochre to bruised purple. After dinner you sink into facing chairs with blankets and a bottle of regional red, watching bats stitch the dusk and the first coyotes start up somewhere below.","category":"relaxation","cost_level":3,"estimated_cost_min":90,"estimated_cost_max":150,"duration_minutes":240,"vibe_tags":["romantic","cozy","chill","foodie"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":["vegetarian","gluten-free"],"search_keywords":["adobe casita","canyon rental","desert cabin","patio grill","southwest getaway"],"venue_type":"casita","setting_type":"desert","intensity_level":2,"quick_filters":["romantic","intellectual"],"reservation_platforms":["airbnb_experiences","google_maps","yelp"]},{"title":"Desert Astronomy Dinner","description":"You're driven out past the last glow of town to a private dark-sky terrace where a chef plates a four-course tasting menu under heat lamps and a sky going indigo. Between courses a guide swings a telescope onto Saturn's rings and the Andromeda smudge, and you trade bites of dessert while the Milky Way arches clean from one horizon to the other.","category":"restaurant","cost_level":4,"estimated_cost_min":175,"estimated_cost_max":320,"duration_minutes":240,"vibe_tags":["romantic","fancy","cultural","foodie"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":["vegetarian","gluten-free","vegan"],"search_keywords":["stargazing dinner","dark sky dining","astronomy experience","telescope dinner","desert fine dining"],"venue_type":"resort","setting_type":"desert","intensity_level":2,"quick_filters":["luxury","romantic","intellectual"],"reservation_platforms":["airbnb_experiences","darksky","resy"]},{"title":"Hay Wagon Harvest Race","description":"You two pile onto a rumbling hay wagon at a working farm, then sprint between rows tossing pumpkins into the cart before the tractor finishes its loop. By the last field you're both sweat-streaked, hay in your hair, laughing too hard to keep score.","category":"outdoor","cost_level":1,"estimated_cost_min":20,"estimated_cost_max":30,"duration_minutes":150,"vibe_tags":["active","fun","adventurous"],"requires_reservation":true,"outdoor_only":true,"seasonal":["fall"],"dietary_friendly":[],"search_keywords":["working farm harvest","hay wagon ride","pumpkin picking farm","U-pick farm activity"],"venue_type":"farm","setting_type":"countryside","intensity_level":3,"quick_filters":["active","fun_silly","low_budget"],"reservation_platforms":["eventbrite","google_maps"]},{"title":"Country Trail Horseback Gallop","description":"You saddle up at a backcountry ranch and follow a guide through wheat fields gone gold, your horse breaking into a canter where the trail opens wide. You catch each other grinning over the thud of hooves, the whole valley rolling out ahead of you.","category":"activity","cost_level":2,"estimated_cost_min":60,"estimated_cost_max":75,"duration_minutes":180,"vibe_tags":["adventurous","active","romantic"],"requires_reservation":true,"outdoor_only":true,"seasonal":null,"dietary_friendly":[],"search_keywords":["guided horseback trail ride","ranch riding lesson","countryside trail ride couples","ranch horseback experience"],"venue_type":"ranch","setting_type":"countryside","intensity_level":3,"quick_filters":["active","romantic"],"reservation_platforms":["airbnb_experiences","yelp","google_maps"]},{"title":"Working Farm Stay Weekend","description":"You wake before dawn in a creaking farmhouse to collect eggs, muck stalls, and learn to hand-milk a goat while the rooster argues with the sunrise. By the second evening you're shelling peas on the porch like you've done it your whole lives, boots caked and hearts full.","category":"outdoor","cost_level":4,"estimated_cost_min":350,"estimated_cost_max":550,"duration_minutes":1440,"vibe_tags":["adventurous","cozy","active"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":[],"search_keywords":["farm stay overnight","agritourism weekend","working farm bed and breakfast","hands-on farm experience couples"],"venue_type":"farmstay","setting_type":"countryside","intensity_level":4,"quick_filters":["active","luxury"],"reservation_platforms":["airbnb_experiences","google_maps"]},{"title":"Hot Air Balloon Over the Valley","description":"You climb into the basket as the burner roars and the farmland drops away beneath you, the patchwork of green and gold tilting in the early light. Floating in total silence between burns, you clink plastic flutes of champagne and feel like the only two people awake on earth.","category":"outdoor","cost_level":4,"estimated_cost_min":300,"estimated_cost_max":500,"duration_minutes":240,"vibe_tags":["adventurous","romantic","fancy"],"requires_reservation":true,"outdoor_only":true,"seasonal":null,"dietary_friendly":[],"search_keywords":["hot air balloon ride countryside","sunrise balloon flight couples","champagne balloon experience","valley balloon tour"],"venue_type":"open field","setting_type":"countryside","intensity_level":4,"quick_filters":["romantic","luxury"],"reservation_platforms":["airbnb_experiences","yelp","google_maps"]},{"title":"Lavender Farm Long Lunch","description":"You wander rows of humming purple at a hillside lavender farm, then settle at a linen-draped table for a slow regional lunch scented with the fields around you. Between courses you cut your own bundle to dry, the whole afternoon unspooling at the pace of the bees.","category":"restaurant","cost_level":3,"estimated_cost_min":90,"estimated_cost_max":140,"duration_minutes":210,"vibe_tags":["romantic","foodie","relaxing"],"requires_reservation":true,"outdoor_only":true,"seasonal":["summer"],"dietary_friendly":["vegetarian","gluten-free"],"search_keywords":["lavender farm lunch","U-pick lavender field","farm table dining countryside","lavender harvest experience"],"venue_type":"farm","setting_type":"countryside","intensity_level":2,"quick_filters":["romantic","luxury"],"reservation_platforms":["opentable","resy","google_maps"]},{"title":"Private Estate Cellar Dinner","description":"You're led down stone steps into a candlelit barrel cellar on a country estate, where a chef plates a multi-course tasting beside the vintner who poured every glass. Surrounded by sleeping oak casks and the cool hush underground, each course feels like a secret meant only for the two of you.","category":"restaurant","cost_level":4,"estimated_cost_min":200,"estimated_cost_max":320,"duration_minutes":210,"vibe_tags":["fancy","romantic","foodie"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":["vegetarian","gluten-free"],"search_keywords":["private cellar tasting dinner","estate barrel room dinner","vintner table experience","countryside winery chef dinner"],"venue_type":"winery","setting_type":"countryside","intensity_level":2,"quick_filters":["luxury","romantic"],"reservation_platforms":["resy","opentable","google_maps"]},{"title":"Tide Pool Reef Walk at Low Tide","description":"You time your morning around the lowest tide, then pick your way barefoot across the exposed reef flat, peering into warm pools where neon wrasse dart and a spiny urchin tucks itself into a crevice. By the time the water creeps back, you've filled your phone with macro shots and your pockets are full of nothing but the salt drying on your skin.","category":"outdoor","cost_level":1,"estimated_cost_min":0,"estimated_cost_max":25,"duration_minutes":150,"vibe_tags":["adventurous","active","chill"],"requires_reservation":false,"outdoor_only":true,"seasonal":null,"dietary_friendly":[],"search_keywords":["tide pools","reef walk","low tide","tropical beach","marine life"],"venue_type":"beach","setting_type":"tropical","intensity_level":3,"quick_filters":["active","low_budget"],"reservation_platforms":["nps","google_maps"]},{"title":"Volcanic Crater Rim Trek","description":"You lace up at dawn and climb the switchbacks of a dormant island volcano, the air thinning and the jungle giving way to rust-red cinder as you go. At the rim you split a warm coconut and stare down into the steaming crater while clouds pour over the ridge below your feet.","category":"outdoor","cost_level":2,"estimated_cost_min":30,"estimated_cost_max":70,"duration_minutes":300,"vibe_tags":["adventurous","active","romantic"],"requires_reservation":true,"outdoor_only":true,"seasonal":null,"dietary_friendly":["vegetarian","vegan","gluten-free"],"search_keywords":["volcano hike","crater rim","island trek","tropical hiking","summit trail"],"venue_type":"trailhead","setting_type":"tropical","intensity_level":3,"quick_filters":["active","low_budget"],"reservation_platforms":["recreation_gov","nps","google_maps"]},{"title":"Liveaboard Reef Diving Weekend","description":"You board a small dive boat at sunset and motor out to a remote atoll, falling asleep to the hull's gentle knock and waking for three dives a day among reef sharks, sea turtles, and walls of glittering fish. Between tanks you nap on the sun deck, rinse the salt from your hair, and watch the Milky Way unspool over water with no land in sight.","category":"outdoor","cost_level":4,"estimated_cost_min":900,"estimated_cost_max":2400,"duration_minutes":2880,"vibe_tags":["adventurous","active","romantic"],"requires_reservation":true,"outdoor_only":true,"seasonal":null,"dietary_friendly":["vegetarian","gluten-free","dairy-free"],"search_keywords":["liveaboard","scuba diving","reef diving","dive boat","atoll"],"venue_type":"dive boat","setting_type":"tropical","intensity_level":4,"quick_filters":["active","luxury"],"reservation_platforms":["airbnb_experiences","google_maps","yelp"]},{"title":"Overwater Bungalow Escape","description":"You step straight off your private deck into bathwater-warm lagoon, then dry off and watch parrotfish drift beneath the glass panel set into your bedroom floor. Dinner arrives by canoe at sunset, and you eat grilled mahi-mahi with your feet dangling over the turquoise, the only sounds the lap of water and each other.","category":"relaxation","cost_level":4,"estimated_cost_min":700,"estimated_cost_max":1800,"duration_minutes":1440,"vibe_tags":["romantic","fancy","relaxing","foodie"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":["gluten-free","dairy-free","vegetarian"],"search_keywords":["overwater bungalow","lagoon resort","island getaway","luxury escape","private deck"],"venue_type":"resort","setting_type":"tropical","intensity_level":2,"quick_filters":["romantic","luxury"],"reservation_platforms":["airbnb_experiences","google_maps","yelp"]},{"title":"Sunset Catamaran Sail with Rum Tasting","description":"You kick off your shoes on the netting at the bow as the catamaran heels into the trade winds, spray catching the last gold light. A crewmember pours flights of aged island rum into your hands while the captain points out the green flash on the horizon and the sails snap overhead.","category":"entertainment","cost_level":3,"estimated_cost_min":90,"estimated_cost_max":150,"duration_minutes":180,"vibe_tags":["romantic","fun","chill","social"],"requires_reservation":true,"outdoor_only":true,"seasonal":null,"dietary_friendly":["vegetarian","gluten-free","vegan"],"search_keywords":["sunset sail","catamaran cruise","rum tasting","trade winds","island sailing"],"venue_type":"catamaran","setting_type":"tropical","intensity_level":2,"quick_filters":["romantic","luxury"],"reservation_platforms":["airbnb_experiences","yelp","google_maps"]},{"title":"Mangrove Kayak and Bioluminescence Paddle","description":"You launch your tandem kayak into a labyrinth of mangrove tunnels in the late afternoon, ducking under arched roots while herons stalk the shallows. Long after dark you slip back out, and every dip of your paddle ignites a swirl of electric-blue plankton beneath the hull like you're stirring the stars themselves.","category":"outdoor","cost_level":2,"estimated_cost_min":50,"estimated_cost_max":75,"duration_minutes":210,"vibe_tags":["adventurous","active","romantic"],"requires_reservation":true,"outdoor_only":true,"seasonal":null,"dietary_friendly":[],"search_keywords":["mangrove kayak","bioluminescence","night paddle","glowing water","tropical estuary"],"venue_type":"estuary","setting_type":"tropical","intensity_level":3,"quick_filters":["active","romantic"],"reservation_platforms":["airbnb_experiences","recreation_gov","google_maps"]},{"title":"Frozen Waterfall Ice Climbing","description":"You strap on crampons and swing twin axes into a curtain of blue glacier-fed ice while your partner belays from the snowpack below, both of you trading nervous laughs that fog the air. By the time you both top out and dangle your boots over the frozen edge, the adrenaline has melted into the kind of grin you only get after surviving something gorgeous together.","category":"outdoor","cost_level":2,"estimated_cost_min":60,"estimated_cost_max":75,"duration_minutes":240,"vibe_tags":["adventurous","active"],"requires_reservation":true,"outdoor_only":true,"seasonal":["winter"],"dietary_friendly":[],"search_keywords":["ice climbing","frozen waterfall","crampons","guided winter climb","belay"],"venue_type":"ice park","setting_type":"cold_weather","intensity_level":3,"quick_filters":["active","intellectual"],"reservation_platforms":["airbnb_experiences","yelp"]},{"title":"Snowshoe Trek to a Backcountry Yurt","description":"You break a fresh trail through knee-deep powder, your breath syncing as the only sound besides snow squeaking under your snowshoes and a distant raven. When the little wood-stove yurt finally appears in a clearing, you pile inside, peel off frozen layers, and feel the heat hit your cheeks like the best secret you've ever shared.","category":"outdoor","cost_level":2,"estimated_cost_min":40,"estimated_cost_max":70,"duration_minutes":300,"vibe_tags":["adventurous","active","cozy"],"requires_reservation":true,"outdoor_only":true,"seasonal":["winter"],"dietary_friendly":[],"search_keywords":["snowshoeing","backcountry yurt","winter trek","powder","warming hut"],"venue_type":"yurt","setting_type":"cold_weather","intensity_level":3,"quick_filters":["active","romantic"],"reservation_platforms":["recreation_gov","airbnb_experiences"]},{"title":"Dog Sledding Expedition with Trail Lunch","description":"You take turns gripping the sled handle and tucking into the basket as a team of huskies tears across a frozen lake, ice fog streaming off their backs and snow spraying your laughing faces. At the turnaround you share a thermos of hot soup beside the dogs and let the wild stillness of the white expanse sink into both of you for hours.","category":"outdoor","cost_level":4,"estimated_cost_min":200,"estimated_cost_max":350,"duration_minutes":360,"vibe_tags":["adventurous","active","foodie"],"requires_reservation":true,"outdoor_only":true,"seasonal":["winter"],"dietary_friendly":["vegetarian"],"search_keywords":["dog sledding","husky mushing","frozen lake","trail lunch","winter expedition"],"venue_type":"kennel","setting_type":"cold_weather","intensity_level":4,"quick_filters":["active","luxury"],"reservation_platforms":["airbnb_experiences","yelp"]},{"title":"Igloo Build & Overnight Sleepout","description":"You spend the golden-hour afternoon sawing snow blocks and spiraling them into a real igloo, arguing happily over the dome's geometry until you crawl inside your candlelit creation. Bundled in zero-degree bags as the temperature drops outside, you watch your breath rise toward the snow ceiling and realize you've never felt so wildly far from everything but each other.","category":"outdoor","cost_level":3,"estimated_cost_min":80,"estimated_cost_max":140,"duration_minutes":1080,"vibe_tags":["adventurous","cozy","creative"],"requires_reservation":true,"outdoor_only":true,"seasonal":["winter"],"dietary_friendly":[],"search_keywords":["igloo building","snow shelter","winter camping","overnight sleepout","quinzhee"],"venue_type":"snow camp","setting_type":"cold_weather","intensity_level":4,"quick_filters":["active","creative"],"reservation_platforms":["airbnb_experiences","recreation_gov"]},{"title":"Frozen Lake Fondue Sleigh Ride","description":"A horse-drawn sleigh carries you across a snow-blanketed valley under fur blankets, bells jingling while the runners hiss over fresh powder toward a lantern-lit lakeside chalet. Inside, you dip crusty bread and roasted vegetables into a bubbling pot of Gruyère, the fire crackling as frost feathers creep up the windows beside your shoulders.","category":"restaurant","cost_level":3,"estimated_cost_min":90,"estimated_cost_max":145,"duration_minutes":180,"vibe_tags":["romantic","cozy","foodie","fancy"],"requires_reservation":true,"outdoor_only":false,"seasonal":["winter"],"dietary_friendly":["vegetarian"],"search_keywords":["sleigh ride","fondue","alpine chalet","horse drawn","winter dinner"],"venue_type":"chalet","setting_type":"cold_weather","intensity_level":2,"quick_filters":["romantic","luxury"],"reservation_platforms":["resy","opentable","yelp"]},{"title":"Glass Igloo Aurora Suite Stay","description":"You check into a heated glass-domed igloo where the entire ceiling frames the snow-laden pines and a sky bruising into green and violet ribbons of aurora. Tucked under heavy duvets with mugs of spiced cider, you keep waking each other all night just to point at the lights dancing over the frozen tundra above your bed.","category":"relaxation","cost_level":4,"estimated_cost_min":350,"estimated_cost_max":600,"duration_minutes":1440,"vibe_tags":["romantic","fancy","cozy","relaxing"],"requires_reservation":true,"outdoor_only":false,"seasonal":["winter"],"dietary_friendly":[],"search_keywords":["glass igloo","aurora borealis","northern lights suite","winter resort","glass dome stay"],"venue_type":"resort","setting_type":"cold_weather","intensity_level":2,"quick_filters":["romantic","luxury"],"reservation_platforms":["airbnb_experiences","darksky"]},{"title":"Trampoline Park Free-Jump Hour","description":"You bounce wall-to-wall across a warehouse of connected trampolines, racing each other into the foam pit until you're both breathless and laughing too hard to stand. The buzzer for the dodgeball court goes off, and you sprint over to settle who's actually got the better arm.","category":"activity","cost_level":1,"estimated_cost_min":20,"estimated_cost_max":30,"duration_minutes":90,"vibe_tags":["fun","active","adventurous"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":[],"search_keywords":["trampoline park","indoor jump","foam pit","dodgeball"],"venue_type":"trampoline park","setting_type":"indoor_only","intensity_level":3,"quick_filters":["active","fun_silly","low_budget"],"reservation_platforms":["google_maps","yelp"]},{"title":"Indoor Surf Wave Session","description":"You take turns on the standing wave at the indoor flow-rider, wiping out spectacularly while the other films it for posterity and shameless replays. By the third round you're both actually carving the foam, trading the board between rides and high-fiving with soaked hands.","category":"activity","cost_level":2,"estimated_cost_min":45,"estimated_cost_max":70,"duration_minutes":90,"vibe_tags":["active","adventurous","fun"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":[],"search_keywords":["indoor surf","flow rider","wave pool","bodyboard session"],"venue_type":"indoor surf park","setting_type":"indoor_only","intensity_level":3,"quick_filters":["active","fun_silly"],"reservation_platforms":["airbnb_experiences","yelp","google_maps"]},{"title":"Indoor Skydiving Flight Pair","description":"You step into the vertical wind tunnel and the 120-mph updraft swallows your nervous laughter as an instructor steadies your spread arms in mid-air. Watching your partner float and spin like they've shed gravity entirely, you can't wipe the grin off your face before it's your turn again.","category":"activity","cost_level":3,"estimated_cost_min":110,"estimated_cost_max":150,"duration_minutes":120,"vibe_tags":["adventurous","active","fun"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":[],"search_keywords":["indoor skydiving","wind tunnel","bodyflight","vertical wind tunnel"],"venue_type":"indoor skydiving facility","setting_type":"indoor_only","intensity_level":4,"quick_filters":["active","luxury","fun_silly"],"reservation_platforms":["airbnb_experiences","google_maps","yelp"]},{"title":"Overnight Museum Sleepover","description":"Long after the public files out, you unroll sleeping bags beneath the suspended whale skeleton and explore darkened galleries with flashlights and a private after-hours guide. You drift off whispering about the dinosaur towering overhead, then wake to a quiet breakfast in a hall that's still entirely yours.","category":"cultural","cost_level":3,"estimated_cost_min":120,"estimated_cost_max":150,"duration_minutes":720,"vibe_tags":["adventurous","cultural","cozy","fun"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":[],"search_keywords":["museum sleepover","overnight museum","after hours museum","adult night at the museum"],"venue_type":"museum","setting_type":"indoor_only","intensity_level":4,"quick_filters":["intellectual","fun_silly"],"reservation_platforms":["eventbrite","google_maps"]},{"title":"Hotel Suite Tasting-Menu Staycation","description":"You check into a downtown suite mid-afternoon, trade real clothes for robes, and let the in-house chef walk a multi-course tasting menu and wine flight straight to your private table by the window. Between courses you sink into the soaking tub and the city glitters below, the night entirely undictated by any closing time.","category":"relaxation","cost_level":4,"estimated_cost_min":350,"estimated_cost_max":600,"duration_minutes":1440,"vibe_tags":["fancy","romantic","relaxing","foodie"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":["vegetarian","gluten-free"],"search_keywords":["luxury hotel staycation","in-suite tasting menu","private dining suite","overnight chef experience"],"venue_type":"hotel","setting_type":"indoor_only","intensity_level":2,"quick_filters":["luxury","romantic"],"reservation_platforms":["resy","opentable","google_maps"]},{"title":"Private Omakase at the Hinoki Counter","description":"You slide onto two seats at a tiny ten-stool counter where the chef builds each piece of nigiri by hand and sets it directly in front of you, narrating the catch as it lands. Knees brushing, you sip cold sake and let the courses unspool for two unhurried hours, the rest of the world sealed out behind the noren curtain.","category":"restaurant","cost_level":4,"estimated_cost_min":200,"estimated_cost_max":320,"duration_minutes":150,"vibe_tags":["fancy","romantic","foodie"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":["gluten-free","dairy-free"],"search_keywords":["omakase","sushi counter","private chef counter","edomae sushi tasting"],"venue_type":"restaurant","setting_type":"indoor_only","intensity_level":2,"quick_filters":["luxury","romantic"],"reservation_platforms":["resy","opentable","yelp"]},{"title":"Living Room Silent Disco Showdown","description":"You each grab a pair of headphones, queue up rival playlists, and turn the living room into a sweat-slicked dance floor where only the two of you can hear the beat. Between songs you trade headphones to guess each other's secret bangers, dissolving into breathless laughter when the slow jam hits mid-jump.","category":"activity","cost_level":1,"estimated_cost_min":0,"estimated_cost_max":20,"duration_minutes":90,"vibe_tags":["fun","active","social"],"requires_reservation":false,"outdoor_only":false,"seasonal":null,"dietary_friendly":[],"search_keywords":["silent disco","wireless headphones","dance party at home","playlist battle"],"venue_type":null,"setting_type":"at_home","intensity_level":3,"quick_filters":["fun_silly","active","low_budget"],"reservation_platforms":[]},{"title":"Furniture-Fort Obstacle Course","description":"You drag every couch cushion, blanket, and dining chair into the middle of the room and build a winding obstacle gauntlet you both have to crawl, hurdle, and army-roll through against the clock. Loser refills the snack bowl, and the rematch always ends with one of you collapsed in a heap of pillows, wheezing with laughter.","category":"activity","cost_level":1,"estimated_cost_min":0,"estimated_cost_max":10,"duration_minutes":75,"vibe_tags":["fun","active","adventurous"],"requires_reservation":false,"outdoor_only":false,"seasonal":null,"dietary_friendly":[],"search_keywords":["indoor obstacle course","pillow fort","living room games","timed challenge"],"venue_type":null,"setting_type":"at_home","intensity_level":3,"quick_filters":["fun_silly","active","low_budget"],"reservation_platforms":[]},{"title":"Dusk-to-Dawn Film Festival Marathon","description":"You curate a five-movie overnight festival with a printed program, intermission snacks staged in advance, and a rule that neither of you can fall asleep before the closing credits of the final feature roll past sunrise. Somewhere around the third film you've built a nest of blankets on the floor, debating plot holes in whispers while the coffee maker waits on standby for the home stretch.","category":"entertainment","cost_level":1,"estimated_cost_min":10,"estimated_cost_max":30,"duration_minutes":600,"vibe_tags":["cozy","fun","chill","social"],"requires_reservation":false,"outdoor_only":false,"seasonal":null,"dietary_friendly":["vegetarian"],"search_keywords":["overnight movie marathon","film festival at home","all night movies","double feature"],"venue_type":null,"setting_type":"at_home","intensity_level":4,"quick_filters":["fun_silly","low_budget"],"reservation_platforms":[]},{"title":"Build-Your-Own Restaurant All-Nighter","description":"You transform the kitchen into a pop-up bistro for one night only, designing a menu, hand-lettering little cards, and cooking a multi-course tasting where one of you plays chef while the other works the candlelit front of house. By the final dessert plating you've swapped aprons three times, dimmed every light, and the dishes can wait until morning because the dancing in the kitchen comes first.","category":"creative","cost_level":2,"estimated_cost_min":40,"estimated_cost_max":75,"duration_minutes":360,"vibe_tags":["romantic","creative","foodie","fancy"],"requires_reservation":false,"outdoor_only":false,"seasonal":null,"dietary_friendly":["vegetarian","gluten-free"],"search_keywords":["home pop-up restaurant","tasting menu at home","multi-course dinner","kitchen date night"],"venue_type":null,"setting_type":"at_home","intensity_level":4,"quick_filters":["romantic","creative"],"reservation_platforms":[]},{"title":"Caviar and Champagne Tasting at the Counter","description":"You set up a small luxury spread on the kitchen counter with tins of caviar, blinis, creme fraiche, and a chilled bottle of grower champagne, learning to taste each one slowly the way the labels suggest. Perched on barstools knee to knee, you rate every pairing on a scorecard and let one good bottle stretch the whole golden-lit evening between you.","category":"restaurant","cost_level":4,"estimated_cost_min":150,"estimated_cost_max":280,"duration_minutes":150,"vibe_tags":["fancy","romantic","foodie","relaxing"],"requires_reservation":false,"outdoor_only":false,"seasonal":null,"dietary_friendly":["gluten-free","nut-free"],"search_keywords":["caviar tasting at home","champagne pairing","luxury home date","blinis and bubbly"],"venue_type":null,"setting_type":"at_home","intensity_level":2,"quick_filters":["luxury","romantic"],"reservation_platforms":[]},{"title":"Omakase Sushi Kit Counter Date","description":"You order a premium chef's sushi kit shipped to your door with sashimi-grade fish, fresh-pressed rice, and a step-by-step guided sequence, then sit at your own makeshift counter rolling and slicing course by course. One of you pours the sake while the other plates each piece, narrating it like a stern but loving sushi master until you're both too full to attempt the dragon roll.","category":"restaurant","cost_level":3,"estimated_cost_min":90,"estimated_cost_max":145,"duration_minutes":150,"vibe_tags":["foodie","creative","fancy","fun"],"requires_reservation":false,"outdoor_only":false,"seasonal":null,"dietary_friendly":["gluten-free","dairy-free"],"search_keywords":["omakase kit at home","sushi making kit","sashimi delivery","DIY nigiri counter"],"venue_type":null,"setting_type":"at_home","intensity_level":3,"quick_filters":["luxury","creative","fun_silly"],"reservation_platforms":[]},{"title":"Korean Spa Bathhouse Day","description":"You drift between the cedar-scented hot pool and the icy plunge, then dare each other into the salt sauna where the heat presses in like a slow exhale. Wrapped in matching robes, you split a bowl of patbingsu in the relaxation lounge and let the whole afternoon dissolve into steam and quiet laughter.","category":"relaxation","cost_level":2,"estimated_cost_min":40,"estimated_cost_max":70,"duration_minutes":240,"vibe_tags":["relaxing","chill","social","cozy"],"requires_reservation":false,"outdoor_only":false,"seasonal":null,"dietary_friendly":["vegetarian"],"search_keywords":["korean spa","jjimjilbang","bathhouse","sauna","hot pool"],"venue_type":"spa","setting_type":"big_city","intensity_level":1,"quick_filters":["romantic","low_budget"],"reservation_platforms":["yelp","google_maps"]},{"title":"Sound Bath in Candlelight","description":"You lie shoulder to shoulder on the floor, eyes closed, as a wash of crystal bowls and chimes rolls over the room and you feel the low notes hum somewhere behind your ribs. When the last tone fades you stay there in the dark a moment longer, fingers loosely laced, both of you reluctant to break the spell.","category":"relaxation","cost_level":1,"estimated_cost_min":20,"estimated_cost_max":30,"duration_minutes":75,"vibe_tags":["relaxing","chill","romantic","cozy"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":[],"search_keywords":["sound bath","crystal bowls","meditation","gong","candlelit"],"venue_type":"studio","setting_type":null,"intensity_level":1,"quick_filters":["romantic","low_budget"],"reservation_platforms":["eventbrite","meetup"]},{"title":"Lakeside Sauna and Cold Dip","description":"You crowd into a wood-fired sauna at the water's edge until the heat is almost too much, then sprint out together and crash into the cold lake, gasping and howling under the open sky. Back inside, dripping and grinning, you ladle more water over the stones and trade the kind of slow, unhurried talk that only happens when you're this warm and this far from your phones.","category":"relaxation","cost_level":2,"estimated_cost_min":50,"estimated_cost_max":75,"duration_minutes":150,"vibe_tags":["relaxing","adventurous","cozy","chill"],"requires_reservation":true,"outdoor_only":true,"seasonal":["fall","winter"],"dietary_friendly":[],"search_keywords":["lakeside sauna","wood fired sauna","cold plunge","nordic sauna","lake dip"],"venue_type":"sauna","setting_type":"countryside","intensity_level":2,"quick_filters":["romantic","active"],"reservation_platforms":["airbnb_experiences","yelp","google_maps"]},{"title":"Hammam Steam Ritual","description":"Beneath a domed ceiling pricked with little stars of light, you take turns being scrubbed and rinsed on the warm marble until your skin tingles and your shoulders finally drop. You end the ritual sipping mint tea on a low cushioned bench, foreheads close, feeling like you've been gently put back together.","category":"relaxation","cost_level":3,"estimated_cost_min":90,"estimated_cost_max":140,"duration_minutes":120,"vibe_tags":["relaxing","romantic","fancy","cultural"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":["vegan","vegetarian"],"search_keywords":["hammam","turkish bath","steam","marble","exfoliation ritual"],"venue_type":"spa","setting_type":"big_city","intensity_level":1,"quick_filters":["romantic","luxury"],"reservation_platforms":["resy","yelp","google_maps"]},{"title":"Forest Bathing Walk","description":"A guide leads you off the trail and asks you to simply notice things, so you spend an unhurried hour pressing palms to bark, watching light filter green through the canopy, and breathing slower than you have all week. By the end you're walking in comfortable silence, hands linked, the city's noise replaced by birdsong and your own steady pulse.","category":"relaxation","cost_level":1,"estimated_cost_min":15,"estimated_cost_max":30,"duration_minutes":120,"vibe_tags":["relaxing","chill","romantic","cultural"],"requires_reservation":true,"outdoor_only":true,"seasonal":["spring","summer","fall"],"dietary_friendly":[],"search_keywords":["forest bathing","shinrin yoku","nature walk","guided meditation","woodland"],"venue_type":null,"setting_type":"mountain","intensity_level":2,"quick_filters":["romantic","low_budget"],"reservation_platforms":["meetup","eventbrite","nps"]},{"title":"Restorative Yoga and Tea Evening","description":"Propped on bolsters and draped in blankets, you melt into long, supported poses while a gentle voice tells you that you don't have to do anything at all right now. Afterward you fold onto floor cushions for a pot of warm tea, both of you a little dazed and softer than when you walked in.","category":"relaxation","cost_level":1,"estimated_cost_min":25,"estimated_cost_max":30,"duration_minutes":90,"vibe_tags":["relaxing","chill","cozy","romantic"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":["vegan","vegetarian","gluten-free"],"search_keywords":["restorative yoga","yin yoga","tea ceremony","bolsters","gentle yoga"],"venue_type":"studio","setting_type":"big_city","intensity_level":1,"quick_filters":["romantic","low_budget"],"reservation_platforms":["meetup","eventbrite","yelp"]},{"title":"Rooftop Thermal Pool Twilight","description":"You sink up to your shoulders in the warm rooftop soaking pool as the sky turns from gold to indigo and the city lights flicker on far below your dangling feet. A server brings infused water and tiny towels, but mostly you just rest your heads back against the tile and watch the first stars arrive over the skyline.","category":"relaxation","cost_level":3,"estimated_cost_min":80,"estimated_cost_max":150,"duration_minutes":150,"vibe_tags":["relaxing","romantic","fancy","chill"],"requires_reservation":true,"outdoor_only":true,"seasonal":["spring","summer","fall"],"dietary_friendly":["vegan","vegetarian"],"search_keywords":["rooftop thermal pool","soaking pool","rooftop spa","warm pool","skyline view"],"venue_type":"spa","setting_type":"big_city","intensity_level":1,"quick_filters":["romantic","luxury"],"reservation_platforms":["resy","opentable","yelp"]},{"title":"Mountain Wellness Resort Overnight","description":"You check into a pine-framed suite and surrender the next eighteen hours to thermal circuit pools, a side-by-side mountain-view massage, and a slow dinner where nobody checks the time. You wake tangled in heavy linens to mist burning off the peaks, order coffee to the room, and agree this is exactly how every weekend should feel.","category":"relaxation","cost_level":4,"estimated_cost_min":350,"estimated_cost_max":650,"duration_minutes":1440,"vibe_tags":["relaxing","romantic","fancy","cozy"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":["vegetarian","vegan","gluten-free"],"search_keywords":["mountain wellness resort","spa resort overnight","thermal circuit","couples retreat","destination spa"],"venue_type":"resort","setting_type":"mountain","intensity_level":2,"quick_filters":["romantic","luxury"],"reservation_platforms":["resy","google_maps","yelp"]},{"title":"Snowshoe Trek to a Warming Hut","description":"You crunch single-file through a hushed pine forest, the only sound your breath and the soft hiss of snow sliding off branches, until a tiny woodstove-warmed hut glows ahead. Inside you peel off frosted layers, pour cocoa from your thermos, and let the heat and the quiet stretch the afternoon out as long as it'll go.","category":"outdoor","cost_level":1,"estimated_cost_min":0,"estimated_cost_max":30,"duration_minutes":240,"vibe_tags":["adventurous","active","cozy"],"requires_reservation":false,"outdoor_only":true,"seasonal":["winter"],"dietary_friendly":["vegetarian","vegan","gluten-free"],"search_keywords":["snowshoeing","warming hut","winter trail","backcountry","trek"],"venue_type":"trailhead","setting_type":"cold_weather","intensity_level":3,"quick_filters":["active","low_budget"],"reservation_platforms":["recreation_gov","nps","google_maps"]},{"title":"Dog Sledding Through the Pines","description":"You both pile onto the sled behind a yipping team of huskies, and the moment the musher releases the brake the world blurs into white birch and flying snow. By the run's end you're laughing through frozen eyelashes, taking turns standing on the runners while the other tucks low against the wind.","category":"outdoor","cost_level":3,"estimated_cost_min":100,"estimated_cost_max":150,"duration_minutes":180,"vibe_tags":["adventurous","fun","active"],"requires_reservation":true,"outdoor_only":true,"seasonal":["winter"],"dietary_friendly":[],"search_keywords":["dog sledding","husky team","mushing","winter tour","snow adventure"],"venue_type":"outfitter","setting_type":"countryside","intensity_level":3,"quick_filters":["active","luxury"],"reservation_platforms":["airbnb_experiences","yelp","google_maps"]},{"title":"Snowstorm Soup-and-Bread Day In","description":"While fat flakes pile against the window, you two camp out in the kitchen all afternoon, you kneading a sticky boule of bread while your partner stirs a pot of something rich and steaming. By the time the loaf comes out golden and the storm hits its peak, you're tearing off warm crusts, dunking them, and agreeing that being snowed in was always the plan.","category":"creative","cost_level":1,"estimated_cost_min":10,"estimated_cost_max":30,"duration_minutes":240,"vibe_tags":["cozy","foodie","chill"],"requires_reservation":false,"outdoor_only":false,"seasonal":["winter"],"dietary_friendly":["vegetarian","vegan","dairy-free"],"search_keywords":["homemade bread","soup","snow day","baking","cozy cooking"],"venue_type":null,"setting_type":"at_home","intensity_level":2,"quick_filters":["low_budget","creative"],"reservation_platforms":[]},{"title":"Sleigh Ride Under Heavy Blankets","description":"You climb onto a horse-drawn sleigh as twilight turns the snowfields lavender, burrowing together under a stack of wool blankets while bells jingle in time with the horses' breath. The driver points out deer tracks and frozen creeks, but mostly you just lean into each other and let the cold sharpen everything warm between you.","category":"outdoor","cost_level":2,"estimated_cost_min":40,"estimated_cost_max":75,"duration_minutes":90,"vibe_tags":["romantic","cozy","relaxing"],"requires_reservation":true,"outdoor_only":true,"seasonal":["winter"],"dietary_friendly":[],"search_keywords":["sleigh ride","horse drawn","winter evening","romantic ride","countryside"],"venue_type":"farm","setting_type":"countryside","intensity_level":1,"quick_filters":["romantic"],"reservation_platforms":["airbnb_experiences","yelp","google_maps"]},{"title":"Alpine Fondue at a Mountain Chalet","description":"After the lifts close you trade ski boots for slippers and slide into a candlelit chalet where a copper pot of melted gruyere bubbles between you. You spear chunks of crusty bread and roasted potatoes, swirl them slow, and watch the last skiers carve down a floodlit slope through the frosted window.","category":"restaurant","cost_level":3,"estimated_cost_min":80,"estimated_cost_max":140,"duration_minutes":150,"vibe_tags":["romantic","fancy","foodie","cozy"],"requires_reservation":true,"outdoor_only":false,"seasonal":["winter"],"dietary_friendly":["vegetarian","gluten-free"],"search_keywords":["alpine fondue","mountain chalet","ski resort dining","cheese fondue","apres ski"],"venue_type":"restaurant","setting_type":"mountain","intensity_level":2,"quick_filters":["romantic","luxury"],"reservation_platforms":["opentable","resy","yelp"]},{"title":"Speakeasy Hop on a Snowy Night","description":"You navigate the slushed-up downtown blocks arm in arm, ducking through an unmarked door into a dim brick room where a piano plays low and the bartender names a cocktail after the storm outside. Three hidden bars and a shared plate of warm spiced nuts later, the snow keeps falling and neither of you wants the night to find its last stop.","category":"entertainment","cost_level":3,"estimated_cost_min":75,"estimated_cost_max":130,"duration_minutes":210,"vibe_tags":["romantic","social","fancy","fun"],"requires_reservation":false,"outdoor_only":false,"seasonal":["winter"],"dietary_friendly":["vegetarian","gluten-free"],"search_keywords":["speakeasy","cocktail crawl","hidden bar","downtown nightlife","winter night out"],"venue_type":"bar","setting_type":"big_city","intensity_level":2,"quick_filters":["romantic","luxury"],"reservation_platforms":["resy","yelp","google_maps"]},{"title":"Indoor Curling Match for Two","description":"You step onto the gleaming sheet of pebbled ice, gripping a forty-pound granite stone for the first time and immediately discovering that sliding it straight is comically harder than it looks. By the end you're both sweeping furiously and trash-talking through giggles, having invented at least three new house rules and one very dramatic victory dance.","category":"activity","cost_level":2,"estimated_cost_min":30,"estimated_cost_max":60,"duration_minutes":120,"vibe_tags":["fun","active","social"],"requires_reservation":true,"outdoor_only":false,"seasonal":["winter"],"dietary_friendly":[],"search_keywords":["curling","indoor ice","learn to curl","winter sport","couples activity"],"venue_type":"curling club","setting_type":"indoor_only","intensity_level":3,"quick_filters":["fun_silly","active"],"reservation_platforms":["eventbrite","meetup","yelp"]},{"title":"Helicopter Skyline Tour","description":"You buckle into the back of a four-seat helicopter, headsets crackling as the rotors spin up and the ground drops away beneath your dangling feet. For the next hour the whole city unspools below in glittering miniature, and you keep squeezing each other's hands every time the pilot banks toward another landmark.","category":"activity","cost_level":4,"estimated_cost_min":300,"estimated_cost_max":600,"duration_minutes":120,"vibe_tags":["adventurous","romantic","fancy"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":[],"search_keywords":["helicopter tour","scenic flight","aerial tour","skyline","private flight"],"venue_type":"helipad","setting_type":null,"intensity_level":4,"quick_filters":["luxury","romantic"],"reservation_platforms":["airbnb_experiences","yelp","google_maps"]},{"title":"Sunrise Hot-Air Balloon Flight","description":"You arrive in the dark to watch the crew unfurl an enormous nylon balloon and breathe it to life with bursts of roaring flame. As you lift silently into the pink dawn, the burner falls quiet, the earth tilts open below you, and you toast the new day with the champagne tucked into the basket.","category":"outdoor","cost_level":4,"estimated_cost_min":250,"estimated_cost_max":500,"duration_minutes":240,"vibe_tags":["adventurous","romantic","fancy"],"requires_reservation":true,"outdoor_only":true,"seasonal":null,"dietary_friendly":["vegetarian","vegan"],"search_keywords":["hot air balloon","sunrise flight","balloon ride","champagne flight"],"venue_type":"launch field","setting_type":null,"intensity_level":4,"quick_filters":["luxury","romantic"],"reservation_platforms":["airbnb_experiences","yelp","google_maps"]},{"title":"Tasting Menu Bar Crawl","description":"You map out three of the most coveted tables in town and book a single dazzling course at each, gliding from a raw-bar amuse to a smoke-domed entree to a theatrical dessert across one long evening. Between stops you walk off the last bite arm in arm, comparing favorites and daring each other to guess the secret ingredient.","category":"restaurant","cost_level":4,"estimated_cost_min":200,"estimated_cost_max":400,"duration_minutes":300,"vibe_tags":["foodie","fancy","romantic","adventurous"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":["vegetarian","gluten-free"],"search_keywords":["tasting menu","chef's table","fine dining crawl","multi-course","degustation"],"venue_type":"restaurant","setting_type":null,"intensity_level":3,"quick_filters":["luxury","romantic"],"reservation_platforms":["resy","opentable","yelp"]},{"title":"Tandem Skydive Together","description":"You shuffle to the open door strapped to your instructors, lock eyes across the screaming wind, and then the floor disappears in one stomach-dropping rush of freefall. Sixty seconds later the canopies snap open in tandem and you drift down side by side, breathless and laughing, the whole horizon laid out beneath your boots.","category":"activity","cost_level":4,"estimated_cost_min":400,"estimated_cost_max":700,"duration_minutes":300,"vibe_tags":["adventurous","active","fun"],"requires_reservation":true,"outdoor_only":true,"seasonal":null,"dietary_friendly":[],"search_keywords":["skydiving","tandem jump","freefall","adrenaline","parachute"],"venue_type":"dropzone","setting_type":null,"intensity_level":4,"quick_filters":["luxury","active"],"reservation_platforms":["airbnb_experiences","yelp","google_maps"]},{"title":"Full-Day Tandem Adventure Package","description":"You sign up for a guided combo day that strings ziplining, a rope-bridge canyon traverse, and a whitewater run into one nonstop blur of harnesses and high-fives. By the time you collapse onto the shuttle bench, mud-streaked and grinning, you've cheered each other across every cliff edge and rapid the guide could throw at you.","category":"activity","cost_level":3,"estimated_cost_min":120,"estimated_cost_max":150,"duration_minutes":480,"vibe_tags":["adventurous","active","fun"],"requires_reservation":true,"outdoor_only":true,"seasonal":null,"dietary_friendly":[],"search_keywords":["adventure package","zipline","whitewater rafting","guided tour","adrenaline day"],"venue_type":"adventure outfitter","setting_type":null,"intensity_level":4,"quick_filters":["active","fun_silly"],"reservation_platforms":["airbnb_experiences","recreation_gov","yelp"]},{"title":"Indoor Skydiving Flight","description":"You zip into matching jumpsuits and step into a roaring vertical wind tunnel where the instructor's hand on your back is the only thing keeping you from cartwheeling. The two of you take turns floating and flailing on a column of air, mouthing exaggerated faces at each other through the glass while the spotter spins you into the air like a kite.","category":"activity","cost_level":2,"estimated_cost_min":60,"estimated_cost_max":120,"duration_minutes":120,"vibe_tags":["adventurous","active","fun","social"],"requires_reservation":true,"outdoor_only":false,"seasonal":null,"dietary_friendly":[],"search_keywords":["indoor skydiving","wind tunnel","bodyflight","iFly","vertical wind tunnel"],"venue_type":"wind tunnel","setting_type":null,"intensity_level":3,"quick_filters":["active","fun_silly"],"reservation_platforms":["airbnb_experiences","yelp","google_maps"]}]$dn$::jsonb) AS x(
